import { randomUUID } from 'crypto';
import { CredentialVault } from './CredentialVault';
import { queries, type SecretCollection } from '../db';

const vault = new CredentialVault();

export interface SecretEntry {
  key: string;
  value: string;
}

export interface SecretCollectionSummary {
  id: string;
  name: string;
  description: string | null;
  tags: string[];
  secretCount: number;
  createdAt: number;
  updatedAt: number;
}

export interface SecretCollectionDetail extends SecretCollectionSummary {
  secrets: SecretEntry[];
}

export interface CreateCollectionInput {
  name: string;
  description?: string;
  tags?: string[];
  secrets: Record<string, string>;
}

export interface UpdateCollectionInput {
  name?: string;
  description?: string | null;
  tags?: string[];
  secrets?: Record<string, string>;
}

class SecretVaultService {
  /**
   * Parse .env file content into key-value pairs.
   * Handles comments, empty lines, quoted values.
   */
  parseEnvContent(content: string): Record<string, string> {
    const result: Record<string, string> = {};
    const lines = content.split('\n');

    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed || trimmed.startsWith('#')) continue;

      const equalIndex = trimmed.indexOf('=');
      if (equalIndex <= 0) continue;

      const key = trimmed.substring(0, equalIndex).trim();
      let value = trimmed.substring(equalIndex + 1).trim();

      // Remove surrounding quotes
      if (
        (value.startsWith('"') && value.endsWith('"')) ||
        (value.startsWith("'") && value.endsWith("'"))
      ) {
        value = value.slice(1, -1);
        value = value.replace(/\\"/g, '"').replace(/\\'/g, "'");
      }

      if (key) result[key] = value;
    }

    return result;
  }

  /**
   * Create a new secret collection (encrypts secrets before storing)
   */
  async createCollection(input: CreateCollectionInput): Promise<SecretCollectionDetail> {
    const id = randomUUID();
    const now = Date.now();
    const secretsJson = JSON.stringify(input.secrets);
    const encryptedData = await vault.encrypt(secretsJson);
    const secretCount = Object.keys(input.secrets).length;

    queries.createSecretCollection({
      id,
      name: input.name,
      description: input.description || null,
      tags: input.tags && input.tags.length > 0 ? JSON.stringify(input.tags) : null,
      encrypted_data: encryptedData,
      secret_count: secretCount,
      created_at: now,
      updated_at: now,
    });

    return {
      id,
      name: input.name,
      description: input.description || null,
      tags: input.tags || [],
      secrets: Object.entries(input.secrets).map(([key, value]) => ({ key, value })),
      secretCount,
      createdAt: now,
      updatedAt: now,
    };
  }

  /**
   * Get all collections (metadata only, no decryption)
   */
  getAllCollections(): SecretCollectionSummary[] {
    const rows = queries.getAllSecretCollections();
    return rows.map((row) => ({
      id: row.id,
      name: row.name,
      description: row.description,
      tags: row.tags ? JSON.parse(row.tags) : [],
      secretCount: row.secret_count,
      createdAt: row.created_at,
      updatedAt: row.updated_at,
    }));
  }

  /**
   * Get a single collection with decrypted secrets
   */
  async getCollectionSecrets(id: string): Promise<SecretCollectionDetail | null> {
    const row = queries.getSecretCollectionById(id);
    if (!row) return null;

    const decrypted = await vault.decrypt(row.encrypted_data);
    const secretsObj: Record<string, string> = JSON.parse(decrypted);

    return {
      id: row.id,
      name: row.name,
      description: row.description,
      tags: row.tags ? JSON.parse(row.tags) : [],
      secrets: Object.entries(secretsObj).map(([key, value]) => ({ key, value })),
      secretCount: row.secret_count,
      createdAt: row.created_at,
      updatedAt: row.updated_at,
    };
  }

  /**
   * Update a collection (re-encrypts secrets if provided)
   */
  async updateCollection(id: string, input: UpdateCollectionInput): Promise<void> {
    const updates: Partial<SecretCollection> = { updated_at: Date.now() };
    if (input.name !== undefined) updates.name = input.name;
    if (input.description !== undefined) updates.description = input.description;
    if (input.tags !== undefined) updates.tags = input.tags.length > 0 ? JSON.stringify(input.tags) : null;

    if (input.secrets !== undefined) {
      const secretsJson = JSON.stringify(input.secrets);
      updates.encrypted_data = await vault.encrypt(secretsJson);
      updates.secret_count = Object.keys(input.secrets).length;
    }

    queries.updateSecretCollection(id, updates);
  }

  /**
   * Delete a collection
   */
  deleteCollection(id: string): void {
    queries.deleteSecretCollection(id);
  }

  /**
   * Get secrets as Record<string, string> for import into env editors
   */
  async getSecretsAsRecord(id: string): Promise<Record<string, string> | null> {
    const row = queries.getSecretCollectionById(id);
    if (!row) return null;

    const decrypted = await vault.decrypt(row.encrypted_data);
    return JSON.parse(decrypted);
  }
}

export const secretVaultService = new SecretVaultService();
